var ensureSerializer = (serialize) => {
  if (serialize) {
    return serialize;
  }
  return (value) => value;
};
var getDataAgentConnectedDataSummary = (options) => {
  const { inconvo: providedInconvo, agentId } = options;
  if (!agentId) {
    throw new Error(
      "getDataAgentConnectedDataSummary requires an agentId value."
    );
  }
  const inconvo = providedInconvo ?? new Inconvo();
  return tool({
    description: "Use this tool before you ask your first question. You will get a high level summary of the connected data. This can be used to get an overview of the data before asking more specific questions.",
    inputSchema: z.object({}),
